// Vikunja outgoing webhook payload (event=task.updated):
// { event_name, time, data: { task: { id, title, description, done, ... } } }
const body = $input.first().json.body || $input.first().json;
const event = body.event_name || body.event || '';
const task = (body.data && body.data.task) || body.task;
if (!task) { throw new Error('Vikunja webhook payload has no `task`'); }
if (event !== 'task.updated' && event !== 'task.created') {
  return [{ json: { skipped: true, reason: `event=${event}` } }];
}
if (!task.done) {
  return [{ json: { skipped: true, reason: 'task not done' } }];
}

// Pull the GitHub issue URL out of the description (placed there by the
// `GitHub Issue → Vikunja Task` workflow).
const desc = task.description || '';
const m = desc.match(/(https?:\/\/github\.com\/([^/\s]+)\/([^/\s]+)\/issues\/(\d+))/);
if (!m) {
  return [{ json: { skipped: true, reason: 'no GitHub issue URL in description' } }];
}
return [{ json: { issue_url: m[1], owner: m[2], repo: m[3], number: parseInt(m[4], 10), task_id: task.id } }];
